const EJSVC  = "service_j2i1xzm";      // e.g. "service_abc123"
const EJSTPL_STAFF  = "template_87rhz6q";   // e.g. "template_staff01"
const EJSTPL_STUDENT = "template_ixzwvpz"; // e.g. "template_student01"
const EJSPK  = "w6ApuWdCxwCf1c-cA";      // e.g. "aBcDeFgHiJkLmNoP"
const CC_EMAIL = "arthur.lewis420@gmail.com";
// ─────────────────────────────────────────────────────────────────────────────

const YOOBEE_B64 = "";
const HEALTH_B64 = "";

const COUNSELLORS = [
  { id:1, name:"Arthur Lewis Test (Billy Cummins)",     role:"Student Counsellor", email:"arthur.lewis420@gmail.com",  phone:"0800 665 544", bio:"Supporting students through stress, personal challenges, and overall wellbeing with a warm and non-judgmental approach.", initials:"BC", color:"#3A7CA5" },
  { id:2, name:"Arthur Lewis Test Two (Deejay Kim)",        role:"Student Counsellor", email:"lnbmerchantprofiledbtest@outlook.com",phone:"0800 665 544", bio:"Here to help students navigate academic pressure, mental health, and life transitions in a safe, confidential space.", initials:"DK", color:"#7C5CBF" },
  { id:3, name:"To Be Announced",   role:"Student Counsellor", email:null,                          phone:"0800 665 544", bio:"A new team member will be joining our counselling team shortly. Check back for availability.", initials:"?", color:"#B0BEC5", disabled:true },
];

const MONTHS=["January","February","March","April","May","June","July","August","September","October","November","December"];
const DAYS_SHORT=["Sun","Mon","Tue","Wed","Thu","Fri","Sat"];
function genSlots(){const s=[];for(let h=9;h<16;h++){s.push(`${String(h).padStart(2,"0")}:00`);s.push(`${String(h).padStart(2,"0")}:30`);}return s;}
const TIME_SLOTS=genSlots();
const REASONS=["Academic stress or pressure","Anxiety or mental health","Personal / family issues","Adjusting to college life","Financial stress","Relationship difficulties","Grief or loss","Other"];
function daysInMonth(y,m){return new Date(y,m+1,0).getDate();}
function firstDay(y,m){return new Date(y,m,1).getDay();}
function isWeekday(y,m,d){const wd=new Date(y,m,d).getDay();return wd>0&&wd<6;}
function isPast(y,m,d){const t=new Date();t.setHours(0,0,0,0);return new Date(y,m,d)<t;}
function formatDate(y,m,d){return `${DAYS_SHORT[new Date(y,m,d).getDay()]} ${d} ${MONTHS[m]} ${y}`;}

const G="linear-gradient(135deg,#2D6A4F,#52B788)";
const gc={fontFamily:"'DM Sans',sans-serif"};

// ── SEND EMAILS via EmailJS ───────────────────────────────────────────────────
async function sendEmails(booking) {
  const { counsellor, details } = booking;
  const params = {
    to_email:       counsellor.email,
    cc_email:       CC_EMAIL,
    reply_to:       details.email,
    counsellor:     counsellor.name,
    student_name:   details.name,
    student_id:     details.studentId,
    student_email:  details.email,
    student_phone:  details.phone,
    reason:         details.reason,
    notes:          details.notes || "None provided",
  };
  // Email 1: notify counsellor (+ CC arthur)
  await emailjs.send(EJSVC, EJSTPL_STAFF, params, EJSPK);
  // Email 2: confirmation to student
  await emailjs.send(EJSVC, EJSTPL_STUDENT, {
    ...params,
    student_email: details.email,
  }, EJSPK);
}

// ── SHARED COMPONENTS ─────────────────────────────────────────────────────────
function Btn({onClick,disabled,children,style={},secondary=false}){
  return(
    <button onClick={onClick} disabled={disabled}
      onMouseEnter={e=>{if(!disabled&&!secondary){e.currentTarget.style.transform="translateY(-1px)";e.currentTarget.style.boxShadow="0 8px 24px rgba(45,106,79,0.4)";}}}
      onMouseLeave={e=>{if(!disabled&&!secondary){e.currentTarget.style.transform="none";e.currentTarget.style.boxShadow="0 4px 16px rgba(45,106,79,0.25)";}}}
      style={{border:"none",borderRadius:12,fontWeight:600,...gc,cursor:disabled?"default":"pointer",transition:"all 0.2s",
        ...(secondary?{background:"#fff",border:"2px solid #E0EDE8",color:"#5A7A72",padding:"13px 20px"}
          :{background:disabled?"#D8E8E0":G,color:disabled?"#A0B8B0":"#fff",padding:"14px 20px",
            boxShadow:disabled?"none":"0 4px 16px rgba(45,106,79,0.25)"}),
        ...style}}>
      {children}
    </button>
  );
}

function Progress({step,total}){
  return(
    <div style={{display:"flex",gap:6,marginBottom:28}}>
      {Array.from({length:total}).map((_,i)=>(
        <div key={i} style={{flex:1,height:4,borderRadius:99,background:i<step?"#2D6A4F":"#E0EDE8",transition:"background 0.4s"}}/>
      ))}
    </div>
  );
}

function Avatar({initials,color,size=60}){
  return(
    <div style={{width:size,height:size,borderRadius:"50%",background:color,display:"flex",alignItems:"center",
      justifyContent:"center",color:"#fff",fontWeight:700,...gc,fontSize:size*0.33,flexShrink:0,
      boxShadow:`0 4px 12px ${color}55`}}>
      {initials}
    </div>
  );
}

// ── Field component at TOP LEVEL so it never re-mounts on re-render (fixes focus bug) ──
function Field({label,value,onChange,type="text",placeholder,required=true,as}){
  const base={width:"100%",padding:"13px 14px",borderRadius:10,border:"2px solid #E8EFED",...gc,
    fontSize:14,color:"#1B2B2A",outline:"none",background:"#FAFCFB",boxSizing:"border-box",transition:"border-color 0.2s"};
  const onF=e=>e.target.style.borderColor="#2D6A4F";
  const onB=e=>e.target.style.borderColor="#E8EFED";
  return(
    <div style={{marginBottom:16}}>
      <label style={{...gc,fontSize:13,fontWeight:600,color:"#3A5A52",display:"block",marginBottom:6}}>
        {label}{required&&<span style={{color:"#E05A5A",marginLeft:3}}>*</span>}
      </label>
      {as==="textarea"?(
        <textarea value={value} onChange={onChange} placeholder={placeholder} rows={3}
          style={{...base,resize:"vertical"}} onFocus={onF} onBlur={onB}/>
      ):as==="select"?(
        <select value={value} onChange={onChange}
          style={{...base,color:value?"#1B2B2A":"#B0C4BC",appearance:"none",cursor:"pointer"}}
          onFocus={onF} onBlur={onB}>
          <option value="" disabled>Select a reason...</option>
          {REASONS.map(r=><option key={r} value={r}>{r}</option>)}
        </select>
      ):(
        <input type={type} value={value} onChange={onChange} placeholder={placeholder}
          style={base} onFocus={onF} onBlur={onB}/>
      )}
    </div>
  );
}

// ── TIME Slot at TOP LEVEL ────────────────────────────────────────────────────
function Slot({slot,selected,onSelect}){
  return(
    <div onClick={()=>onSelect(slot)}
      style={{padding:"13px 6px",borderRadius:10,textAlign:"center",...gc,fontSize:14,fontWeight:500,
        border:selected?"2px solid #2D6A4F":"2px solid #E8EFED",
        background:selected?"#2D6A4F":"#fff",color:selected?"#fff":"#3A5A52",
        cursor:"pointer",transition:"all 0.15s",
        boxShadow:selected?"0 4px 12px rgba(45,106,79,0.2)":"none"}}>
      {slot}
    </div>
  );
}

