// ── DATE ──────────────────────────────────────────────────────────────────────
function SelectDate({date,setDate}){
  const today=new Date();
  const [view,setView]=useState({year:today.getFullYear(),month:today.getMonth()});
  const days=daysInMonth(view.year,view.month);
  const fd=firstDay(view.year,view.month);
  const prevM=()=>setView(v=>v.month===0?{year:v.year-1,month:11}:{year:v.year,month:v.month-1});
  const nextM=()=>setView(v=>v.month===11?{year:v.year+1,month:0}:{year:v.year,month:v.month+1});
  return(
    <div>
      <h2 style={{fontFamily:"'Playfair Display',serif",fontSize:24,color:"#1B2B2A",margin:"0 0 4px"}}>Preferred Date</h2>
      <p style={{...gc,color:"#7A9990",fontSize:14,margin:"0 0 22px"}}>Weekdays only · Mon – Fri</p>
      <div style={{background:"#fff",borderRadius:18,padding:22,boxShadow:"0 4px 20px rgba(0,0,0,0.07)"}}>
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:16}}>
          <button onClick={prevM} style={{background:"none",border:"none",fontSize:22,cursor:"pointer",color:"#2D6A4F",padding:"4px 10px",lineHeight:1}}>‹</button>
          <span style={{...gc,fontWeight:700,color:"#1B2B2A",fontSize:16}}>{MONTHS[view.month]} {view.year}</span>
          <button onClick={nextM} style={{background:"none",border:"none",fontSize:22,cursor:"pointer",color:"#2D6A4F",padding:"4px 10px",lineHeight:1}}>›</button>
        </div>
        <div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",textAlign:"center",marginBottom:6}}>
          {DAYS_SHORT.map(d=><div key={d} style={{...gc,fontSize:11,color:"#A0B8B4",fontWeight:700,padding:"4px 0"}}>{d}</div>)}
        </div>
        <div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",gap:3}}>
          {Array.from({length:fd}).map((_,i)=><div key={`e${i}`}/>)}
          {Array.from({length:days}).map((_,i)=>{
            const d=i+1;const wk=isWeekday(view.year,view.month,d);const past=isPast(view.year,view.month,d);
            const sel=date&&date.year===view.year&&date.month===view.month&&date.day===d;const dis=!wk||past;
            return(
              <div key={d} onClick={()=>!dis&&setDate({year:view.year,month:view.month,day:d})}
                style={{textAlign:"center",padding:"10px 2px",borderRadius:9,...gc,fontSize:13,
                  background:sel?"#2D6A4F":"transparent",color:sel?"#fff":dis?"#D8E0DE":"#1B2B2A",
                  cursor:dis?"default":"pointer",fontWeight:sel?700:400,transition:"background 0.15s",lineHeight:1}}>
                {d}
              </div>
            );
          })}
        </div>
      </div>
      {date&&(
        <div style={{marginTop:14,padding:"12px 16px",background:"#F0FAF5",borderRadius:10,borderLeft:"3px solid #2D6A4F"}}>
          <span style={{...gc,fontSize:13,color:"#2D6A4F",fontWeight:600}}>✓ {formatDate(date.year,date.month,date.day)}</span>
        </div>
      )}
    </div>
  );
}

// ── TIME ──────────────────────────────────────────────────────────────────────
function SelectTime({time,setTime}){
  const morning=TIME_SLOTS.slice(0,6);
  const afternoon=TIME_SLOTS.slice(6);
  const LabelRow=({text})=>(<p style={{...gc,fontSize:11,fontWeight:700,color:"#9AB8B0",textTransform:"uppercase",letterSpacing:1,margin:"16px 0 10px"}}>{text}</p>);
  return(
    <div>
      <h2 style={{fontFamily:"'Playfair Display',serif",fontSize:24,color:"#1B2B2A",margin:"0 0 4px"}}>Preferred Time</h2>
      <p style={{...gc,color:"#7A9990",fontSize:14,margin:"0 0 4px"}}>30-minute sessions · New Zealand Time</p>
      <LabelRow text="Morning"/>
      <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:8}}>
        {morning.map(s=><Slot key={s} slot={s} selected={time===s} onSelect={setTime}/>)}
      </div>
      <LabelRow text="Afternoon"/>
      <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:8}}>
        {afternoon.map(s=><Slot key={s} slot={s} selected={time===s} onSelect={setTime}/>)}
      </div>
    </div>
  );
}

// ── STUDENT DETAILS ───────────────────────────────────────────────────────────
function StudentDetails({details,setDetails}){
  const upd=(k,v)=>setDetails(d=>({...d,[k]:v}));
  return(
    <div>
      <h2 style={{fontFamily:"'Playfair Display',serif",fontSize:24,color:"#1B2B2A",margin:"0 0 4px"}}>Your Details</h2>
      <p style={{...gc,color:"#7A9990",fontSize:14,margin:"0 0 22px"}}>All information is kept strictly confidential 🔒</p>
      <Field label="Full Name" value={details.name||""} onChange={e=>upd("name",e.target.value)} placeholder="e.g. Jane Smith"/>
      <Field label="Student ID" value={details.studentId||""} onChange={e=>upd("studentId",e.target.value)} placeholder="e.g. 12345678"/>
      <Field label="Email Address" type="email" value={details.email||""} onChange={e=>upd("email",e.target.value)} placeholder="your@email.com"/>
      <Field label="Phone Number" type="tel" value={details.phone||""} onChange={e=>upd("phone",e.target.value)} placeholder="e.g. 021 123 4567"/>
      <Field label="Reason for Visit" as="select" value={details.reason||""} onChange={e=>upd("reason",e.target.value)} placeholder=""/>
      <Field label="Additional Notes" as="textarea" required={false} value={details.notes||""} onChange={e=>upd("notes",e.target.value)} placeholder="Anything else you'd like us to know before your appointment..."/>
    </div>
  );
}

