// ── APP ───────────────────────────────────────────────────────────────────────
export default function App(){
  const[step,setStep]=useState(0);
  const[counsellor,setCounsellor]=useState(null);
  const[details,setDetails]=useState({});
  const[submitting,setSubmitting]=useState(false);
  const[submitted,setSubmitted]=useState(false);
  const[error,setError]=useState(null);

  const TOTAL=3;
  const canNext=[true,!!counsellor,
    !!(details.name&&details.studentId&&details.email&&details.phone&&details.reason),true];

  const handleSubmit=async()=>{
    setSubmitting(true);
    setError(null);
    try {
      await sendEmails({counsellor,details});
    } catch(err){
      console.error("EmailJS error:",err);
      setError("Could not send email. Please check your EmailJS config or try again.");
      setSubmitting(false);
      return;
    }
    setSubmitting(false);
    setSubmitted(true);
  };

  const reset=()=>{setStep(0);setCounsellor(null);setDetails({});setSubmitted(false);setError(null);};
  const booking={counsellor,details};

  return(
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@400;600;700&family=DM+Sans:wght@300;400;500;600&display=swap');
        *{box-sizing:border-box;margin:0;padding:0;}
        body{background:#EEF5F1;}
        input::placeholder,textarea::placeholder{color:#B8CEC9;}
        select option{color:#1B2B2A;}
      `}</style>
      
      <div style={{minHeight:"100vh",background:"linear-gradient(150deg,#E4F2EB 0%,#F5F0EA 55%,#EAF0F5 100%)",
        display:"flex",alignItems:"flex-start",justifyContent:"center",padding:"28px 16px 60px"}}>
        <div style={{width:"100%",maxWidth:480,background:"rgba(255,255,255,0.95)",borderRadius:26,
          padding:"32px 30px",boxShadow:"0 24px 64px rgba(0,0,0,0.11),0 4px 16px rgba(0,0,0,0.05)",
          backdropFilter:"blur(12px)"}}>
          {!submitted&&step>0&&<Progress step={step} total={TOTAL}/>}
          {submitted?<Success booking={booking} onReset={reset}/>
          :step===0?<Welcome onStart={()=>setStep(1)}/>
          :step===1?<SelectCounsellor selected={counsellor} onSelect={c=>{setCounsellor(c);}}/>
          :step===2?<StudentDetails details={details} setDetails={setDetails}/>
          :<Review booking={booking} onSubmit={handleSubmit} submitting={submitting} error={error}/>}
          {!submitted&&step>0&&step<3&&(
            <div style={{display:"flex",gap:10,marginTop:28}}>
              <Btn secondary onClick={()=>setStep(s=>s-1)} style={{flex:1}}>← Back</Btn>
              <Btn onClick={()=>setStep(s=>s+1)} disabled={!canNext[step]} style={{flex:2}}>Continue →</Btn>
            </div>
          )}
          {!submitted&&step===3&&(
            <div style={{marginTop:16}}>
              <Btn secondary onClick={()=>setStep(2)} style={{width:"100%",textAlign:"center",display:"block"}}>← Edit Details</Btn>
            </div>
          )}
        </div>
      </div>
    </>
  );
}